namespace CourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
        new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and human civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, functions, and object-oriented design.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and has published extensively on programming pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
        new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques.", Credits = 4, Schedule = "Tue/Thu 10:00–11:20 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and competitive programming. Former ACM ICPC world finalist.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
        new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Design and implementation of relational databases, SQL, normalization, and transaction processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Rodriguez", InstructorBio = "Dr. Rodriguez spent a decade at Oracle before joining academia. Her research focuses on distributed databases.", DepartmentId = 1, DepartmentName = "Computer Science" },
        new() { Id = 4, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Alan Whitfield", InstructorBio = "Dr. Whitfield is an award-winning educator known for making calculus accessible to all students.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
        new() { Id = 5, Code = "MATH 201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to data science.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma's research bridges pure mathematics and machine learning applications.", DepartmentId = 2, DepartmentName = "Mathematics" },
        new() { Id = 6, Code = "MATH 301", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Alan Whitfield", InstructorBio = "Dr. Whitfield is an award-winning educator known for making calculus accessible to all students.", DepartmentId = 2, DepartmentName = "Mathematics" },
        new() { Id = 7, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM + Fri Lab", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an experimental physicist whose work on quantum optics has been featured in Nature.", DepartmentId = 3, DepartmentName = "Physics" },
        new() { Id = 8, Code = "PHYS 201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Mon/Wed 10:00–11:20 AM + Thu Lab", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an experimental physicist whose work on quantum optics has been featured in Nature.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
        new() { Id = 9, Code = "ENG 101", Title = "College Composition", Description = "Develop critical reading, analytical writing, and research skills for academic success.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. Linda Hayes", InstructorBio = "Prof. Hayes is a published author and has mentored hundreds of student writers over her 20-year career.", DepartmentId = 4, DepartmentName = "English" },
        new() { Id = 10, Code = "ENG 220", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present day.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", InstructorName = "Prof. Linda Hayes", InstructorBio = "Prof. Hayes is a published author and has mentored hundreds of student writers over her 20-year career.", DepartmentId = 4, DepartmentName = "English" },
        new() { Id = 11, Code = "HIST 101", Title = "World History I", Description = "Survey of world civilizations from ancient times through the Renaissance.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is an archaeologist-turned-historian who brings artifacts and primary sources into the classroom.", DepartmentId = 5, DepartmentName = "History" },
        new() { Id = 12, Code = "HIST 250", Title = "Modern European History", Description = "Europe from the Enlightenment through the 20th century, including political revolutions and world wars.", Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is an archaeologist-turned-historian who brings artifacts and primary sources into the classroom.", DepartmentId = 5, DepartmentName = "History" },
    ];

    private readonly List<EnrollmentRequest> _enrollments = [];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public void SubmitEnrollment(EnrollmentRequest request) => _enrollments.Add(request);
}

