        new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques.", Credits = 4, Schedule = "Tue/Thu 10:00–11:20 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and competitive programming. Former ACM ICPC world finalist.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
