@page "/courses"
@inject CourseCatalog.Services.CatalogService Catalog

<PageTitle>Courses</PageTitle>

<h1>Courses</h1>

<form method="get" action="/courses" data-enhance>
    <div class="row g-2 mb-4">
        <div class="col-md-6">
            <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor..." />
        </div>
        <div class="col-md-4">
            <select name="departmentId" class="form-select">
                <option value="">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button type="submit" class="btn btn-primary w-100">Filter</button>
        </div>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<CourseCatalog.Models.Course> courses = [];
    private List<CourseCatalog.Models.Department> departments = [];

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

@page "/enroll"
@inject CourseCatalog.Services.CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received.</p>
    </div>
    <a href="/courses">Browse more courses</a>
}
else
{
    <p>Fill out the form below to request enrollment in a course.</p>

    <form method="post" data-enhance>
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(course.Id == Model.CourseId)">@course.Code - @course.Title</option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm] public CourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<CourseCatalog.Models.Course> courses = [];
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();

        if (!submitted && CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }

        if (HttpMethods.IsPost(HttpContext.Request.Method) && !string.IsNullOrWhiteSpace(Model.StudentName) && !string.IsNullOrWhiteSpace(Model.StudentId) && Model.CourseId > 0)
        {
            Catalog.SubmitEnrollment(Model);
            selectedCourseTitle = courses.FirstOrDefault(c => c.Id == Model.CourseId)?.Title ?? "Unknown";
            submitted = true;
        }
    }

    [CascadingParameter] public HttpContext HttpContext { get; set; } = default!;
}

